#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, B; scanf("%d %d", &N, &B);
        int cnt = 0;
        int cur = (1 << 30) - 1; // all lower 30 bits set
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if ((x & B) == B) {
                ++cnt;
                cur &= x;
            }
        }
        if (cnt > 0 && cur == B) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

